1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const basePremium = (item: { type: string }): number =>
11	  BASE_PREMIUMS[item.type] ?? 0;
12	
13	export const processSteps = (customer: unknown, steps: Array<{ op: string; items: Array<{ type: string }> }>): unknown =>
14	  steps.map((step) => ({
15	    premium: step.items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE,
16	  }));
